// Explicitly aggregate per-channel upload IDs (no Object.assign).
// Rule: nested { storyId, videoType, youtube: { kyaHoAgar, cuteLittleElephant, chizoKiKahani, nutriToon } }.
const items = $input.all();

const pick = (key) => {
  for (const it of items) {
    const v = it.json && it.json[key];
    if (v !== undefined && v !== null && v !== '') return v;
  }
  return null;
};

const body = $('Video Ready Webhook').item.json.body || {};

const aggregated = {
  storyId:     body.story_id,
  videoType:   body.video_type,
  videoUrl:    body.video_url,
  captionText: (body.title || '') + ' #reels #viral',
  node:        '17841445298218124',
  youtube: {
    kyaHoAgar:          pick('kyaHoAgar'),
    cuteLittleElephant: pick('cuteLittleElephant'),
    chizoKiKahani:      pick('chizoKiKahani'),
    nutriToon:          pick('nutriToon')
  },
  // Back-compat flat fields kept so existing downstream expressions keep working
  kyaHoAgar:          pick('kyaHoAgar'),
  cuteLittleElephant: pick('cuteLittleElephant'),
  chizoKiKahani:      pick('chizoKiKahani'),
  nutriToon:          pick('nutriToon'),
  youtubeVideoId:     pick('youtubeVideoId')
};

// Cross-content guard: refuse if a forbidden channel slot was populated for the videoType
const FORBIDDEN = {
  object_talking: ['chizoKiKahani', 'nutriToon'],
  food_discovery: ['kyaHoAgar', 'cuteLittleElephant']
};
const bad = (FORBIDDEN[aggregated.videoType] || []).filter(k => aggregated.youtube[k]);
if (bad.length) {
  throw new Error('Routing violation: ' + aggregated.videoType + ' produced upload(s) for forbidden channel(s): ' + bad.join(', '));
}

return [{ json: aggregated }];

