const rows = $input.all()

let result = [];

rows.forEach(r => {
  const value = r.json.data;

  if (value) {
    // split comma values
    const parts = value.split(",");

    parts.forEach(p => {
      const clean = p.trim().toLowerCase();
      if (clean) result.push(clean);
    });
  }
});

return [
  {
    json: {
      data: result
    }
  }
];

